import { useRef, useState } from "react";
import { useNavigate } from 'react-router-dom';
import { FaCheck } from "react-icons/fa";


//components
import {FetchApi}  from "../../../Controller/FetchApi";
import {retornaApenasNumeros } from "../../../Controller/funcoesVariadas";
import { mascaraDinheiro } from "../../../Controller/funcoesVariadas";
import { validaCampo } from "../../../Controller/funcoesVariadas";
import TelinhaEscolhaClientes from '../../Clientes/TelinhaEscolhaClientes';
import BuscaDetalhadaClientes from '../../Clientes/BuscaDetalhadaClientes';
import CampoSelecaoBrinquedos from '../../Brinquedos/CampoSelecaoBrinquedos';
const {consultaGet} = FetchApi;
//import brinquedosVagos from "../../../Model/BrinquedosVagos";


function NovoEvento(){
    const [listaDeBrinquedosVagos, setListaDeBrinquedosVagos] = useState([]);    
    const [listaDeClientes, setListaDeClientes] = useState([]);
    const [buscaDetalhadaCliente, setBuscaDetalhadaCliente] = useState(false);
    const [clienteEscolhido, setClienteEscolhido] = useState({});

    const [validaCampos, setValidaCampos] = useState([true, true, true, true, true, true, true]);
    
    const [validaNome, setValidaNome] = useState(true);
    const [validaData, setValidaData] = useState(true);
    const [validaLogradouro, setValidaLogradouro] = useState(true);
    const [validaNumero, setValidaNumero] = useState(true);
    const [validaBairro, setValidaBairro] = useState(true);
    const [validaCidade, setValidaCidade] = useState(true);
    const [validaTotal, setValidaTotal] = useState(true);
    const navigate = useNavigate();


    let listaDeBrinquedosEscolhidos = [];
    let ultimoEventoDoClienteEscolhido = [];

    //referências nos campos do formulário
    const nome_cliente = useRef('');
    const data_evento = useRef('');     
    const logradouro_evento = useRef('');
    const numero_evento = useRef(''); 
    const complemento_endereco_evento = useRef('');
    const observacao_endereco_evento = useRef('');
    const bairro_evento = useRef('');
    const cidade_evento = useRef('');
    const valor_total = useRef('');
    const valor_desconto = useRef('');
    const valor_sinal = useRef('');
    const valor_final = useRef('');
    const observacao = useRef('');

    function handleListaDeBrinquedosEscolhidos(brinquedo){
        listaDeBrinquedosVagos.forEach((brinquedoNaLista)=>{
            if(brinquedo.id_brinquedo === brinquedoNaLista.id_brinquedo){
                brinquedoNaLista.qtdSelecionada = brinquedo.qtdSelecionada;
                listaDeBrinquedosEscolhidos.push(brinquedoNaLista);
            }
        });
        console.log(listaDeBrinquedosEscolhidos);
    }

    async function solicitarListaDeBrinquedosVagos(e){
        let dataConsulta = e.target.value;
        let brinquedosVagos = await consultaGet('/brinquedos/data/'+dataConsulta);
        
        console.log(brinquedosVagos);
        setListaDeBrinquedosVagos(brinquedosVagos.resultado);
    }

    //funções da pesquisa detalhada de cliente
    function abrirFormFiltrarCliente(){
        if(buscaDetalhadaCliente){
            setBuscaDetalhadaCliente(false);
        }else {
            setBuscaDetalhadaCliente(true);
            setListaDeClientes([]);
            document.getElementById("nome_cliente").value = '';
        }
    }

    function handleBotaoPesquisarCliente(e){
        e.preventDefault();
        abrirFormFiltrarCliente();
    }

    async function handleClienteEscolhidoNaPesquisaDetalhada(cliente){
        abrirFormFiltrarCliente();
        pegarUltimoEventoClienteEscolhido(cliente);
    }

    //fim das funções da pesquisa detalhada de cliente

    async function carregarListaDeClientes(e){
        let nomeConsultaCliente = e.target.value;
        console.log(e.target.value);
        let listaDeClientesProv;
        if(!nomeConsultaCliente){
            setListaDeClientes([]);
            setClienteEscolhido({});
            ultimoEventoDoClienteEscolhido = [];
            document.getElementById("logradouro_evento").value = '';
            document.getElementById("numero_evento").value = '';
            document.getElementById("complemento_endereco_evento").value = '';
            document.getElementById("observacao_endereco_evento").value = '';
            document.getElementById("bairro_evento").value = '';
            document.getElementById("cidade_evento").value = '';
            
        }else if(!isNaN(nomeConsultaCliente)){
            listaDeClientesProv = await consultaGet('/cliente/'+nomeConsultaCliente);
            console.log(listaDeClientesProv.cliente);
            if(listaDeClientesProv && 'cliente' in listaDeClientesProv && listaDeClientesProv.cliente.status){
                setListaDeClientes([...listaDeClientesProv.cliente.resultado]);
            }
        }else{
            if(nomeConsultaCliente.length < 3){
                listaDeClientesProv = [];
            }else{
                listaDeClientesProv = await consultaGet('/cliente/'+nomeConsultaCliente);
                console.log(listaDeClientesProv.cliente);
                if(listaDeClientesProv && 'cliente' in listaDeClientesProv && listaDeClientesProv.cliente.status){
                    setListaDeClientes([...listaDeClientesProv.cliente.resultado]);
                }
            }
        }       
    }

    async function handleSelecaoCliente(idCliente){
        listaDeClientes.forEach((cliente) => { 
            if(cliente.id_cliente === idCliente){
                pegarUltimoEventoClienteEscolhido(cliente);
                return;
            }
        });
        setListaDeClientes([]);
    }

    async function pegarUltimoEventoClienteEscolhido(cliente){
        document.getElementById("nome_cliente").value = cliente.nome;
        ultimoEventoDoClienteEscolhido = await consultaGet('/ultimoEvento/'+cliente.id_cliente);
        ultimoEventoDoClienteEscolhido.evento[0] && (ultimoEventoDoClienteEscolhido = ultimoEventoDoClienteEscolhido.evento[0]);
        ultimoEventoDoClienteEscolhido.logradouro_evento && (document.getElementById("logradouro_evento").value = ultimoEventoDoClienteEscolhido.logradouro_evento);
        ultimoEventoDoClienteEscolhido.numero_evento && (document.getElementById("numero_evento").value = ultimoEventoDoClienteEscolhido.numero_evento);
        ultimoEventoDoClienteEscolhido.complemento_evento && (document.getElementById("complemento_endereco_cliente").value = ultimoEventoDoClienteEscolhido.complemento_evento);
        ultimoEventoDoClienteEscolhido.observacao_endereco_evento && (document.getElementById("observacao_endereco_cliente").value = ultimoEventoDoClienteEscolhido.observacao_endereco_evento);
        ultimoEventoDoClienteEscolhido.bairro_evento && (document.getElementById("bairro_evento").value = ultimoEventoDoClienteEscolhido.bairro_evento);
        ultimoEventoDoClienteEscolhido.cidade_evento && (document.getElementById("cidade_evento").value = ultimoEventoDoClienteEscolhido.cidade_evento);
    }

    function selecionaTodaPalavra(e){
        e.target.select();
    }

    function fechaValor(e){
        let valor = e.target.value;
        e.target.value = mascaraDinheiro(retornaApenasNumeros(valor));

        document.getElementById('valor_final').value = (

            mascaraDinheiro(Number(retornaApenasNumeros(valor_total.current.value)) - Number(retornaApenasNumeros(valor_desconto.current.value)) - Number(retornaApenasNumeros(valor_sinal.current.value)))
        )

        
    }
    
    function cancelar(e){
        e.preventDefault();
        navigate('/', {replace: true});
    }

    
    async function handleSubmit(e){
        e.preventDefault();
        
        let camposAValidar = document.getElementsByClassName('required');
        console.log(camposAValidar[2].value);
        let camposInvalidos = [];
        
        for(let campo of camposAValidar){
            if(campo.value === ''){
                camposInvalidos.push(false);
            }else{
                camposInvalidos.push(true);
            }
        }
        console.log(camposInvalidos);

        setValidaCampos(camposInvalidos);      


        let evento = {
            cliente: {
              id_cliente: 4,
              nome: 'Elizandra Guasselli Dariva ',
              cpf: '641151004',
              logradouro: 'Estrada da laguna 9990',
              numero: 9990,
              complemento: '',
              observacao_endereco: '',
              cidade: '',
              telefone: '51981321070',
              telefone_recado: '5181588354',
              email: 'elizandra_dariva@hotmail.com',
              observacao_cliente: '',
              cliente_evento: null,
              bairro: null,
              data_nascimento: null
            },
            brinquedos: [
              {
                id_brinquedo: 1,
                nome_brinquedo: 'cama elastica 2,5m',
                valor_brinquedo: 120,
                quantidade: 1,
                caracteristicas: 'Suporta até 100kg',
                foto_brinquedo: 'cama_25.jpg',
                observacao: 'Nenhuma',
                esta_disponivel: null
              },
              {
                id_brinquedo: 3,
                nome_brinquedo: 'toboga ',
                valor_brinquedo: 170,
                quantidade: 1,
                caracteristicas: 'Altura 2,6m, largura 2,6m, comprimento 3m.',
                foto_brinquedo: 'toboga_sem_fundo_de_lado.png',
                observacao: 'Trocar cobertura. ',
                esta_disponivel: null
              }
            ],
            evento: {
              data: '2024-03-08',
              logradouro: 'Estrada da laguna 9990',
              numero: '9990',
              complemento: '',
              observacao_endereco: '',
              bairro: 'Zona Norte',
              cidade: 'Capão da Canoa',
              valor_total: '500',
              valor_desconto: '20',
              valor_sinal: '20',
              observacao_evento: ''
            }
          }
        //let resp = await FetchApi.insercaoPost('/evento', evento);
        console.log(evento);
    }

    function setCustomValidity(e){
        console.log(e);
    }
//onChange={(e) => solicitarListaDeBrinquedosVagos(e)}
    return(
        <div id='container-novo-evento' className="container">
            <div>
                <h2>Novo Evento</h2>
                <p className="letraVermelha">* campos obrigatórios</p>
            </div>

            <form onSubmit={(e) => handleSubmit(e)} noValidate >
                <div>
                    <fieldset className="fieldset">
                        <div className="responsiva form-flex">                                                         
                            <div>
                                <label>Nome do Cliente</label>
                            </div>
                            <div>
                                <button onClick={(e) => handleBotaoPesquisarCliente(e)} id="btn-cliente" className="linkFake">Pesquisar cliente</button>
                                {buscaDetalhadaCliente? <BuscaDetalhadaClientes escolherCliente = {handleClienteEscolhidoNaPesquisaDetalhada} abrirFormFiltrarCliente={abrirFormFiltrarCliente}/> : ''}
                            </div>
                        </div>
                        <div>
                            <p className="letraVermelha campoObrigatorio">*</p>
                            <input type='text' ref={nome_cliente} id="nome_cliente" name='nome_cliente' onChange={(e) => carregarListaDeClientes(e)} 
                            onClick={(e) => selecionaTodaPalavra(e)} placeholder="Cliente" className="form-control required"
                            required />
                            {!validaCampos[0] && <div className="invalid-feedback">Faltou selecionar um cliente</div>}
                        </div>

                        {listaDeClientes.length > 0? <TelinhaEscolhaClientes listaDeClientes={listaDeClientes} handleSelecaoCliente={handleSelecaoCliente} /> : ''}
                    </fieldset>
                    
                    
                </div>
                <fieldset className="espacoAntes fieldset">
                    <label>Data do Evento</label>   
                    <p className="letraVermelha campoObrigatorio">*</p>
                    <div className="letrasVermelhas">Faltou selecionar uma data</div>             
                    <input type='date' id='data_evento' ref={data_evento}  onBlur={(e) => validaCampo(e)} className="required" required />
                    <FaCheck color="green" size="25" className="naoExibir"/>
                    
                    <label>Local do Evento</label>
                    <p className="letraVermelha campoObrigatorio">*</p>
                    <input type='text' maxLength='200' id="logradouro_evento" ref={logradouro_evento} name='logradouro_evento' placeholder="Rua, Avenida, etc..." required className="required" />
                    {!validaCampos[2] && <div className="invalid-feedback">Faltou informar o nome da rua, av., etc...</div>}

                    <p className="letraVermelha campoObrigatorio">*</p>
                    <input type='text' id="numero_evento" name='numero_evento' ref={numero_evento} placeholder="Número" className=" required"/>
                    {!validaCampos[3] && <div className="invalid-feedback">Faltou informar o número do imóvel</div>}

                    <input type='text' maxLength='100' id="complemento_endereco_evento" ref={complemento_endereco_evento} name='complemento_endereco_cliente' placeholder="Referência, Condomínio, Quadra, Lote, etc..." className="form-control"/>
                    <input type='text' maxLength='100' id="observacao_endereco_evento" ref={observacao_endereco_evento} name='observacao_endereco_cliente' placeholder="Cor da casa, etc..." className="form-control"/>
                    
                    <p className="letraVermelha campoObrigatorio">*</p>
                    <input type='text' maxLength='100' id="bairro_evento" ref={bairro_evento} name='bairro_evento' placeholder="Bairro" className="required" required />
                    {!validaCampos[4] && <div className="invalid-feedback">Faltou o bairro do evento</div>}

                    <p className="letraVermelha campoObrigatorio">*</p>
                    <input type='text' maxLength='45' id="cidade_evento" ref={cidade_evento} name='cidade_evento' placeholder="Cidade" className="required" required />
                    {!validaCampos[5] && <div className="invalid-feedback">Faltou a cidade do evento</div>}
                </fieldset>

                <fieldset className="espacoAntes fieldset">
                    <label>Valor do evento</label>
                    <p className="letraVermelha campoObrigatorio">*</p>
                    <input type='text' id='valor_total' ref={valor_total} placeholder="Valor Total" onChange={fechaValor} onClick={(e) => selecionaTodaPalavra(e)} name='valor_total' className="required" required />
                    {!validaCampos[6] && <div className="invalid-feedback">Faltou o valor total</div>}
                    
                    <input type='text' id='valor_desconto' ref={valor_desconto} name='valor_desconto' onChange={fechaValor} onClick={(e) => selecionaTodaPalavra(e)} placeholder="Desconto" className="form-control"/>
                    <input type='text' id='valor_sinal' ref={valor_sinal} name='valor_sinal' onChange={fechaValor} onClick={(e) => selecionaTodaPalavra(e)} placeholder="Sinal" className="form-control"/>
                    <input type='text' id='valor_final' ref={valor_final} name='valor_final' onChange={fechaValor} placeholder="Valor Final" className="form-control" required disabled/>
                    
                    <input type='text' id='observacao' ref={observacao} name='observacao' placeholder="Observação" className="form-control"/>
                </fieldset>

                <CampoSelecaoBrinquedos listaDeBrinquedosVagos={listaDeBrinquedosVagos} 
                                        listaDeBrinquedosEscolhidos={listaDeBrinquedosEscolhidos}/>

                <div>
                    <button className="btn btn-primary">Gravar Evento</button>
                    <button onClick={cancelar} className="btn btn-danger espacoAntes">Cancelar</button>
                </div>
            </form>

        </div>
    );
}


export default NovoEvento;
